  plant_code STRING,
  plant_name STRING,
  country STRING,
  last_posting DATE,
  proposed_lifecycle STRING,
  confirmed_lifecycle STRING,
  effective_lifecycle STRING,
  review_status STRING,
  reviewed_by STRING,
  notes STRING
) USING DELTA;

